import { useState } from 'react';

const countries = ['France', 'Germany', 'Finland', 'Greece', 'Hungary'];

function CountrySearch() {
  const [query, setQuery] = useState('');

  const results = countries.filter(country =>
    country.toLowerCase().includes(query.toLowerCase())
  );

  return (
    <div>
      <input
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search countries..."
      />
      <ul>
        {results.map(country => (
          <li key={country}>{country}</li>
        ))}
      </ul>
    </div>
  );
}

import { useState } from 'react';

function TaskList() {
  const [tasks, setTasks] = useState([
    { id: 1, text: 'Write tests' },
    { id: 2, text: 'Review PR' },
    { id: 3, text: 'Deploy build' },
  ]);

  function removeTask(id) {
    // Keep every task whose id is NOT the one being removed
    setTasks(tasks.filter(task => task.id !== id));
  }

  return (
    <ul>
      {tasks.map(task => (
        <li key={task.id}>
          {task.text}
          <button onClick={() => removeTask(task.id)}>✕</button>
        </li>
      ))}
    </ul>
  );
}

function JobBoard({ jobs }) {
  const [activeFilter, setActiveFilter] = useState('all');

  const visible = activeFilter === 'all'
    ? jobs
    : jobs.filter(job => job.type === activeFilter);

  return (
    <div>
      <div className="filters">
        {['all', 'fulltime', 'parttime', 'remote'].map(f => (
          <button
            key={f}
            onClick={() => setActiveFilter(f)}
            className={activeFilter === f ? 'active' : ''}
          >
            {f}
          </button>
        ))}
      </div>
      <ul>
        {visible.map(job => (
          <li key={job.id}>{job.title} — {job.company}</li>
        ))}
      </ul>
    </div>
  );
}

function ActiveProductList({ products }) {
  return (
    <ul>
      {products
        .filter(p => p.inStock && p.price < 100)  // keep available affordable items
        .map(p => (                                 // transform each to JSX
          <li key={p.id}>
            {p.name} — ${p.price}
          </li>
        ))
      }
    </ul>
  );
}

function ActiveProductList({ products }) {
  const affordable = products.filter(p => p.inStock && p.price < 100);

  if (affordable.length === 0) {
    return <p>No products match.</p>;
  }

  return (
    <ul>
      {affordable.map(p => (
        <li key={p.id}>{p.name} — ${p.price}</li>
      ))}
    </ul>
  );
}

