function TaskBoard({ tasks, currentUserId, priorityFilter, page, pageSize }) {
  const visible = tasks
    .filter(t => !t.completed)                          // hide done tasks
    .filter(t => t.assigneeId === currentUserId)         // my tasks only
    .filter(t => priorityFilter === 'all' || t.priority === priorityFilter)
    .slice((page - 1) * pageSize, page * pageSize);      // paginate

  return (
    <ul>
      {visible.map(task => (
        <li key={task.id}>
          [{task.priority}] {task.title}
        </li>
      ))}
    </ul>
  );
}

