// ❌ splice() mutates the array — never do this to React state
function removeTask(index) {
  tasks.splice(index, 1);       // mutates original array
  setTasks(tasks);              // React may not re-render (same reference)
}

// ✅ filter() returns a new array — React detects the change and re-renders
function removeTask(id) {
  setTasks(tasks.filter(task => task.id !== id));
}

